<script setup lang="ts">import { onMounted,ref } from 'vue';import { useRoute } from 'vue-router';import { Loading } from '@element-plus/icons-vue';import { http,messageOf } from '@/api/http';const route=useRoute(),info=ref<any>(),error=ref(''),incompatible=ref(false),playTracked=ref(false);onMounted(async()=>{try{info.value=(await http.get(`/videos/public/${route.params.id}`)).data;if(info.value.status==='DISABLED')error.value='视频已停用';else void http.post(`/videos/public/${route.params.id}/view`).catch(()=>{})}catch(e){error.value=messageOf(e)}});function trackPlay(){if(playTracked.value)return;playTracked.value=true;void http.post(`/videos/public/${route.params.id}/play`).catch(()=>{})}</script>
<template><main class="player-page"><div v-if="error" class="state"><h1>{{error}}</h1></div><div v-else-if="!info" class="state"><el-icon class="is-loading" size="28"><Loading/></el-icon></div><div v-else class="wrap"><video controls playsinline preload="metadata" :src="`/api/videos/public/${route.params.id}/stream`" @play="trackPlay" @error="incompatible=true">您的客户端不支持视频播放。</video><div class="meta"><h1>{{info.name}}</h1><p v-if="incompatible">当前客户端不兼容该视频格式，请尝试其他浏览器或客户端。</p></div></div></main></template>
<style scoped>.player-page{min-height:100vh;background:#0c0d0f;color:#fff;display:flex;align-items:center;justify-content:center}.wrap{width:min(1200px,100%)}video{display:block;width:100%;max-height:82vh;background:#000}.meta{padding:16px 20px}.meta h1{font-size:17px;margin:0;font-weight:500}.meta p{margin:12px 0 0;color:#fca5a5;font-size:14px}.state{text-align:center;padding:30px}.state h1{font-size:18px;font-weight:500;color:#d1d5db}</style>
